patch:
diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCalls.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCalls.cpp
index c55c40c88bc8..9275f7f247e0 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCalls.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCalls.cpp
@@ -2229,6 +2229,16 @@ Instruction *InstCombinerImpl::visitCallInst(CallInst &CI) {
         return BitOp;
     }

+    // fshl(x, 0, y) --> shl x, y if y is in range [0, BitWidth)
+    // This holds because fshl only uses bits from the first argument when
+    // the second argument is 0, and the shift amount is effectively the same.
+    if (IID == Intrinsic::fshl && match(Op1, m_ZeroInt())) {
+      ConstantRange ShAmtRange = computeConstantRangeIncludingKnownBits(
+          II->getArgOperand(2), /*ForSigned=*/false,
+          SQ.getWithInstruction(II));
+      if (!ShAmtRange.isWrappedSet() && ShAmtRange.getUpper().ule(BitWidth))
+        return BinaryOperator::CreateShl(Op0, II->getArgOperand(2));
+    }
     // Left or right might be masked.
     if (SimplifyDemandedInstructionBits(*II))
       return &CI;

